3	export type Customer = {
4	  yearsWithMHPCO: number;
5	  previousContracts?: number;
6	};
7	
8	export type Item = {
9	  type: string;
10	  material?: string;
11	  enchantment?: number;
12	  cursed?: boolean;
13	};
14	
15	export type QuoteInput = {
16	  customer: Customer;
17	  items: Item[];
18	};
19	
20	const PROCESSING_FEE = 5;
21	const FIRST_INSURANCE_RATE = 0.1;
22	
23	const ITEM_BASE_PREMIUMS: Record<string, number> = {
24	  sword: 100,
25	  amulet: 60,
26	  staff: 80,
27	  potion: 40,
28	  rune: 25,
29	};
30	
31	export function quote(input: QuoteInput): number {
32	  const policyBase = input.items.reduce(
33	    (sum, item) => sum + ITEM_BASE_PREMIUMS[item.type],
34	    0
35	  );
36	  const firstInsuranceSurcharge = policyBase * FIRST_INSURANCE_RATE;
37	  return Math.ceil(policyBase + firstInsuranceSurcharge + PROCESSING_FEE);
38	}
